mapper.select:
SELECT u.id, u.email, u.username, u.nickname, u.avatar_url, u.bio, u.status, u.created_at, u.updated_at, GROUP_CONCAT(DISTINCT r.role_code ORDER BY r.id SEPARATOR ',') AS role_codes FROM users u LEFT JOIN user_roles ur ON ur.user_id = u.id LEFT JOIN roles r ON r.id = ur.role_id AND r.status = 1
AND ( u.email LIKE CONCAT('%', #{queryDTO.keyword}, '%') OR u.username LIKE CONCAT('%', #{queryDTO.keyword}, '%') OR u.nickname LIKE CONCAT('%', #{queryDTO.keyword}, '%') )
AND u.status = #{queryDTO.status}
AND EXISTS ( SELECT 1 FROM user_roles ur INNER JOIN roles r ON r.id = ur.role_id WHERE ur.user_id = u.id AND r.role_code = #{queryDTO.roleCode} AND r.status = 1 )
AND u.created_at >= #{queryDTO.createdStart}
AND u.created_at <= #{queryDTO.createdEnd}
GROUP BY u.id, u.email, u.username, u.nickname, u.avatar_url, u.bio, u.status, u.created_at, u.updated_at ORDER BY u.created_at DESC, u.id DESC
